def char_count(s: str) -> dict:
    """统计字符串中每个字符出现的次数"""
    count = {}
    for char in s:
        count[char] = count.get(char, 0) + 1
    return count

# 使用示例
print(char_count('hello'))  # {'h': 1, 'e': 1, 'l': 2, 'o': 1}
```

